Here's the full pattern:

**XAML — wrap CollectionView in RefreshView for pull-to-refresh:**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                        <Label Text="{Binding Name}" FontAttributes="Bold" />
                        <Label Text="{Binding Description}" FontSize="12"
                               TextColor="{StaticResource Gray500}" />
                    </VerticalStackLayout>
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalTextAlignment="Center"
                   VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel (using CommunityToolkit.Mvvm):**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? selectedItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Must set false to dismiss spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (SelectedItem is null) return;

        await Shell.Current.GoToAsync($"detail?id={SelectedItem.Id}");
        SelectedItem = null; // Reset so the same item can be re-selected
    }
}
```

**Key binding points:**

| XAML property | ViewModel property | Why |
|---|---|---|
| `IsRefreshing` | `bool IsRefreshing` | Two-way — set `false` when done to hide the spinner |
| `Command` (RefreshView) | `RefreshCommand` | Generated by `[RelayCommand]` on `RefreshAsync` |
| `SelectedItem` | `Item? SelectedItem` | Two-way so the VM can null it after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires when selection changes; triggers navigation |
| `ItemsSource` | `ObservableCollection<Item>` | **Must** be `ObservableCollection`, not `List`, for live UI updates |

**Important notes:**
- Always set `IsRefreshing = false` in a `finally` block — otherwise the spinner gets stuck on errors.
- Null out `SelectedItem` after navigating so the user can tap the same item again.
- Update the collection on the **UI thread** via `MainThread.BeginInvokeOnMainThread`.
- Set `x:DataType` on the `DataTemplate` for compiled bindings.
